   286→/// MinefieldBehavior - Handles landmine functionality
   287→/// 
   288→/// This complex behavior manages landmine mechanics including:
   289→/// - Multiple virtual mines per object
   290→/// - Detonation based on collision and relationships
   291→/// - Immunity system for mine-clearing units
   292→/// - Movement animation after placement
   293→/// - Health-based mine depletion
   294→/// - Regeneration tied to creator survival
   295→#[derive(Debug)]
   296→pub struct MinefieldBehavior {
   297→    /// Reference to the object this behavior is attached to
   298→    object: Arc<Mutex<dyn Object>>,
   299→    /// Configuration data for this behavior
   300→    module_data: Arc<MinefieldBehaviorModuleData>,
   301→    /// Reference to game systems
   302→    game_logic: Arc<dyn GameLogic>,
   303→    weapon_store: Arc<dyn WeaponStore>,
   304→    terrain_logic: Arc<dyn TerrainLogic>,
   305→    global_data: Arc<dyn GlobalData>,
   306→
   307→    /// Next frame to check if creator is dead
   308→    next_death_check_frame: UnsignedInt,
   309→    /// Frames remaining for scooting movement
   310→    scoot_frames_left: UnsignedInt,
   311→    /// Velocity for scooting movement
   312→    scoot_vel: Coord3D,
   313→    /// Acceleration for scooting movement
   314→    scoot_accel: Coord3D,
   315→    /// Number of virtual mines remaining
   316→    virtual_mines_remaining: UnsignedInt,
   317→    /// Objects immune to detonation (mine clearers)
   318→    immunes: Vec<ImmuneInfo>,
   319→    /// Objects that have detonated this mine
   320→    detonators: Vec<DetonatorInfo>,
   321→    /// Whether to ignore damage (for internal health changes)
   322→    ignore_damage: Bool,
   323→    /// Whether this mine regenerates
   324→    regenerates: Bool,
   325→    /// Whether health is draining due to creator death
   326→    draining: Bool,
   327→}
   328→
   329→impl MinefieldBehavior {
   330→    /// Maximum number of immune objects to track
   331→    const MAX_IMMUNITY: usize = 3;
   332→
   333→    /// Creates a new MinefieldBehavior
   334→    pub fn new(
   335→        object: Arc<Mutex<dyn Object>>,
   336→        module_data: Arc<MinefieldBehaviorModuleData>,
   337→        game_logic: Arc<dyn GameLogic>,
   338→        weapon_store: Arc<dyn WeaponStore>,
   339→        terrain_logic: Arc<dyn TerrainLogic>,
   340→        global_data: Arc<dyn GlobalData>,
   341→    ) -> Self {
   342→        let mut behavior = Self {
   343→            object,
   344→            module_data: Arc::clone(&module_data),
   345→            game_logic,
   346→            weapon_store,
   347→            terrain_logic,
   348→            global_data,
   349→            next_death_check_frame: 0,
   350→            scoot_frames_left: 0,
   351→            scoot_vel: Coord3D::zero(),
   352→            scoot_accel: Coord3D::zero(),
   353→            virtual_mines_remaining: module_data.num_virtual_mines,
   354→            immunes: vec![ImmuneInfo::new(); Self::MAX_IMMUNITY],
   355→            detonators: Vec::new(),
   356→            ignore_damage: false,
   357→            regenerates: module_data.regenerates,
   358→            draining: false,
   359→        };
   360→
   361→        // Set initial object status - mines aren't auto-acquirable
   362→        if let Ok(mut obj) = behavior.object.lock() {
   363→            obj.set_status(OBJECT_STATUS_NO_ATTACK_FROM_AI);
   364→        }
   365→
   366→        behavior
   367→    }
   368→
   369→    /// Gets the module data for this behavior
   370→    pub fn get_minefield_behavior_module_data(&self) -> &MinefieldBehaviorModuleData {
   371→        &self.module_data
   372→    }
   373→
   374→    /// Gets a reference to the object this behavior is attached to
   375→    pub fn get_object(&self) -> Arc<Mutex<dyn Object>> {
   376→        Arc::clone(&self.object)
   377→    }
   378→
   379→    /// Calculates appropriate sleep time based on current state
   380→    fn calc_sleep_time(&self) -> UpdateSleepTime {
   381→        // If we're draining health, update every frame
   382→        if self.draining {
   383→            return UPDATE_SLEEP_NONE;
   384→        }
   385→
   386→        // If we're scooting, update every frame
   387→        if self.scoot_frames_left > 0 {
   388→            return UPDATE_SLEEP_NONE;
   389→        }
   390→
   391→        // If monitoring immunity, update every frame
   392→        for immune in &self.immunes {
   393→            if immune.id != INVALID_ID {
   394→                return UPDATE_SLEEP_NONE;
   395→            }
   396→        }
   397→
   398→        let mut sleep_time = FOREVER;
   399→        let now = self.game_logic.get_frame();
   400→
   401→        // Sleep until next death check if we care about creator death
   402→        if self.regenerates && self.module_data.stops_regen_after_creator_dies {
   403→            sleep_time = sleep_time.min(self.next_death_check_frame.saturating_sub(now));
   404→        }
   405→
   406→        // Prevent 0 frame sleeps
   407→        if sleep_time == 0 {
   408→            sleep_time = 1;
   409→        }
   410→
   411→        sleep_time
   412→    }
   413→
   414→    /// Detonates the mine once at the given position
   415→    fn detonate_once(&mut self, position: &Coord3D) -> Result<(), Box<dyn std::error::Error>> {
   416→        // Fire detonation weapon
   417→        if let Some(ref weapon) = self.module_data.detonation_weapon {
   418→            let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   419→            self.weapon_store.create_and_fire_temp_weapon(&**weapon, &*object, position)?;
   420→        }
   421→
   422→        // Decrement virtual mine count
   423→        if self.virtual_mines_remaining > 0 {
   424→            self.virtual_mines_remaining -= 1;
   425→        }
   426→
   427→        // Handle destruction or health reduction
   428→        if !self.regenerates && self.virtual_mines_remaining == 0 {
   429→            self.game_logic.destroy_object(Arc::clone(&self.object))?;
   430→        } else {
   431→            // Reduce health based on mine depletion
   432→            let percent = self.virtual_mines_remaining as Real / self.module_data.num_virtual_mines as Real;
   433→            
   434→            if let Ok(mut object) = self.object.lock() {
   435→                if let Some(body) = object.get_body_module() {
   436→                    let mut body_guard = body.lock().map_err(|_| "Failed to lock body")?;
   437→                    let health = body_guard.get_health();
   438→                    let desired = percent * body_guard.get_max_health();
   439→                    let desired = desired.max(MIN_HEALTH);
   440→                    let amount = health - desired;
   441→
   442→                    if amount > 0.0 {
   443→                        self.ignore_damage = true;
   444→                        
   445→                        let mut damage_info = DamageInfo {
   446→                            amount,
   447→                            source_id: object.get_id(),
   448→                            damage_type: DamageType::Unresistable,
   449→                            death_type: DeathType::None,
   450→                        };
   451→                        
   452→                        drop(body_guard);
   453→                        object.attempt_damage(&mut damage_info)?;
   454→                        
   455→                        self.ignore_damage = false;
   456→                    }
   457→                }
   458→            }
   459→        }
   460→
   461→        // Update visual state based on mine count
   462→        if let Ok(mut object) = self.object.lock() {
   463→            if self.virtual_mines_remaining == 0 {
   464→                object.set_model_condition_state(ModelCondition::Rubble);
   465→                object.set_status(OBJECT_STATUS_MASKED);
   466→            } else {
   467→                object.clear_model_condition_state(ModelCondition::Rubble);
   468→                object.clear_status(OBJECT_STATUS_MASKED);
   469→            }
   470→        }
   471→
   472→        // Execute object creation list
   473→        if let Some(ref ocl) = self.module_data.ocl {
   474→            let object = self.object.lock().map_err(|_| "Failed to lock object")?;
   475→            ocl.create(&*object, Some(&*object))?;
   476→        }
   477→
   478→        Ok(())
   479→    }
   480→
   481→    /// Sets parameters for "scooting" movement after mine placement
   482→    pub fn set_scoot_parms(&mut self, start: &Coord3D, end: &Coord3D) -> Result<(), Box<dyn std::error::Error>> {
   483→        let scoot_time = self.module_data.scoot_from_starting_point_time;
   484→        
   485→        let mut end_on_ground = end.clone();
   486→        end_on_ground.z = self.terrain_logic.get_ground_height(end_on_ground.x, end_on_ground.y);
   487→
   488→        let mut scoot_time = scoot_time;
   489→        
   490→        // Adjust scoot time based on fall duration
   491→        if start.z > end_on_ground.z {
   492→            let fall_time = (2.0 * (start.z - end_on_ground.z) / self.global_data.get_gravity().abs()).sqrt();
   493→            let fall_frames = fall_time.ceil() as UnsignedInt;
   494→            if scoot_time < fall_frames {
   495→                scoot_time = fall_frames;
   496→            }
   497→        }
   498→
   499→        if scoot_time == 0 {
   500→            // No scooting - place immediately
   501→            if let Ok(mut object) = self.object.lock() {
   502→                object.set_position(&end_on_ground);
   503→            }
   504→            self.scoot_frames_left = 0;
   505→        } else {
   506→            // Calculate scooting physics
   507→            let dx = end_on_ground.x - start.x;
   508→            let dy = end_on_ground.y - start.y;
   509→            let dz = end_on_ground.z - start.z;
   510→            let dist = (dx * dx + dy * dy).sqrt();
   511→            
   512→            if dist <= 0.1 && dz.abs() <= 0.1 {
   513→                // Too close - place immediately
   514→                if let Ok(mut object) = self.object.lock() {
   515→                    object.set_position(&end_on_ground);
   516→                }
   517→                self.scoot_frames_left = 0;
   518→            } else {
   519→                // Set up scooting motion
   520→                let t = scoot_time as Real;
   521→                let speed = dist / t;
   522→                let accel_mag = (2.0 * (dist - speed * t) / (t * t)).abs();
   523→                
   524→                let dx_norm = if dist <= 0.1 { 0.0 } else { dx / dist };
   525→                let dy_norm = if dist <= 0.1 { 0.0 } else { dy / dist };
   526→                
   527→                self.scoot_vel.x = dx_norm * speed;
   528→                self.scoot_vel.y = dy_norm * speed;
   529→                self.scoot_vel.z = 0.0;
   530→                
   531→                self.scoot_accel.x = -dx_norm * accel_mag;
   532→                self.scoot_accel.y = -dy_norm * accel_mag;
   533→                self.scoot_accel.z = self.global_data.get_gravity();
   534→                
   535→                if let Ok(mut object) = self.object.lock() {
   536→                    object.set_position(start);
   537→                }
   538→                
   539→                self.scoot_frames_left = scoot_time;
   540→            }
   541→        }
   542→
   543→        Ok(())
   544→    }
