   546→    /// Disarms the mine (for mine clearing operations)
   547→    pub fn disarm(&mut self) -> Result<(), Box<dyn std::error::Error>> {
   548→        if !self.regenerates {
   549→            self.game_logic.destroy_object(Arc::clone(&self.object))?;
   550→            return Ok(());
   551→        }
   552→
   553→        // Reduce health to minimum but don't destroy
   554→        if let Ok(mut object) = self.object.lock() {
   555→            if let Some(body) = object.get_body_module() {
   556→                let mut body_guard = body.lock().map_err(|_| "Failed to lock body")?;
   557→                let health = body_guard.get_health();
   558→                let amount = health - MIN_HEALTH;
   559→
   560→                if amount > 0.0 {
   561→                    self.ignore_damage = true;
   562→                    
   563→                    let mut damage_info = DamageInfo {
   564→                        amount,
   565→                        source_id: object.get_id(),
   566→                        damage_type: DamageType::Unresistable,
   567→                        death_type: DeathType::None,
   568→                    };
   569→                    
   570→                    drop(body_guard);
   571→                    object.attempt_damage(&mut damage_info)?;
   572→                    
   573→                    self.ignore_damage = false;
   574→                }
   575→            }
   576→        }
   577→
   578→        self.virtual_mines_remaining = 0;
   579→        
   580→        if let Ok(mut object) = self.object.lock() {
   581→            object.set_model_condition_state(ModelCondition::Rubble);
   582→            object.set_status(OBJECT_STATUS_MASKED);
   583→        }
   584→
   585→        Ok(())
   586→    }
